  ('elementary-c5fb3965-moex-00115', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '關於申請改名之證明文件及戶政機關查證戶籍資料，下列敘述何者錯誤？', '["因與祖父名字完全相同之申請改名案件，逕由戶政機關查證戶籍資料", "因與公司同仁姓名完全相同之申請改名案件，須由公司出具證明文件", "因與同時在臺北市設籍6個月以上且姓名完全相同之申請改名案件，逕由戶政機關查證戶籍資料", "因特殊原因改名者，由戶政機關查證申請人之改名次數及是否成年戶籍資料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
