  ('elementary-c5fb3965-moex-00117', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-bdc7da1c', 'sub-elementary-c5fb3965-03', NULL, 'single_choice', '外國人與我國國民結婚，其姓名使用，下列何者不符規定？', '["辦理結婚登記時應以書面確定其中文姓名", "已取用中文姓名為戶籍結婚登記後，得申請更改中文姓名1次", "與國民所生子女取用中文姓名，應符合國民使用姓名之習慣且須依民法辦理", "於歸化案許可前結婚，但於許可後辦理結婚登記時，可另取中文姓名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:05+00:00", "source_pdf_sha1": "f19cf4640384", "answer_pdf_sha1": "3b4f60409dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
